import { MinPriorityQueue } from '@datastructures-js/priority-queue';

function solve(grid, k) {
    const m = grid.length;
    const n = grid[0].length;
    const dirs = [[0, 1], [1, 0]]; // right and down
    const visited = new Array(m).fill().map(() => 
        new Array(n).fill().map(() => new Array(k + 1).fill(Infinity))
    );
    const pq = new MinPriorityQueue({ priority: (x) => x[0] });
    pq.enqueue([0, 0, 0, k]);
    visited[0][0][k] = 0;

    while (!pq.isEmpty()) {
        const [cost, i, j, remainingK] = pq.dequeue().element;
        if (i === m - 1 && j === n - 1) {
            return cost;
        }
        if (cost > visited[i][j][remainingK]) {
            continue;
        }
        // Normal moves
        for (const [di, dj] of dirs) {
            const ni = i + di;
            const nj = j + dj;
            if (ni < 0 || ni >= m || nj < 0 || nj >= n) {
                continue;
            }
            const newCost = cost + grid[ni][nj];
            if (newCost < visited[ni][nj][remainingK]) {
                visited[ni][nj][remainingK] = newCost;
                pq.enqueue([newCost, ni, nj, remainingK]);
            }
        }
        // Teleport move
        if (remainingK > 0) {
            for (let x = 0; x < m; x++) {
                for (let y = 0; y < n; y++) {
                    if (x === i && y === j) continue;
                    if (grid[x][y] <= grid[i][j]) {
                        if (cost < visited[x][y][remainingK - 1]) {
                            visited[x][y][remainingK - 1] = cost;
                            pq.enqueue([cost, x, y, remainingK - 1]);
                        }
                    }
                }
            }
        }
    }
    return -1;
}

