package main

import (
	"container/heap"
)

type Item struct {
	cost      int64
	i, j      int
	remaining int64
	index     int
}

type PriorityQueue []*Item

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool {
	return pq[i].cost < pq[j].cost
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
	pq[i].index = i
	pq[j].index = j
}

func (pq *PriorityQueue) Push(x interface{}) {
	n := len(*pq)
	item := x.(*Item)
	item.index = n
	*pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	old[n-1] = nil
	item.index = -1
	*pq = old[0 : n-1]
	return item
}

func solve(grid [][]int64, k int64) int64 {
	m := len(grid)
	n := len(grid[0])
	dirs := [][]int{{0, 1}, {1, 0}}
	visited := make([][][]int64, m)
	for i := range visited {
		visited[i] = make([][]int64, n)
		for j := range visited[i] {
			visited[i][j] = make([]int64, k+1)
			for l := range visited[i][j] {
				visited[i][j][l] = 1 << 60
			}
		}
	}

	pq := make(PriorityQueue, 0)
	heap.Init(&pq)
	heap.Push(&pq, &Item{0, 0, 0, k, 0})
	visited[0][0][k] = 0

	for pq.Len() > 0 {
		item := heap.Pop(&pq).(*Item)
		cost, i, j, remaining := item.cost, item.i, item.j, item.remaining
		if i == m-1 && j == n-1 {
			return cost
		}
		if cost > visited[i][j][remaining] {
			continue
		}
		for _, dir := range dirs {
			ni, nj := i+dir[0], j+dir[1]
			if ni < 0 || ni >= m || nj < 0 || nj >= n {
				continue
			}
			newCost := cost + grid[ni][nj]
			if newCost < visited[ni][nj][remaining] {
				visited[ni][nj][remaining] = newCost
				heap.Push(&pq, &Item{newCost, ni, nj, remaining, 0})
			}
		}
		if remaining > 0 {
			for x := 0; x < m; x++ {
				for y := 0; y < n; y++ {
					if x == i && y == j {
						continue
					}
					if grid[x][y] <= grid[i][j] {
						if cost < visited[x][y][remaining-1] {
							visited[x][y][remaining-1] = cost
							heap.Push(&pq, &Item{cost, x, y, remaining - 1, 0})
						}
					}
				}
			}
		}
	}
	return -1
}
