        for (const [di, dj] of dirs) {
            const ni = i + di;
            const nj = j + dj;
            if (ni < 0 || ni >= m || nj < 0 || nj >= n) {
                continue;
            }
            const newCost = cost + grid[ni][nj];
            if (newCost < visited[ni][nj][remainingK]) {
                visited[ni][nj][remainingK] = newCost;
                pq.enqueue([newCost, ni, nj, remainingK]);
            }
        }
        // Teleport move
        if (remainingK > 0) {
            for (let x = 0; x < m; x++) {
                for (let y = 0; y < n; y++) {
                    if (x === i && y === j) continue;
                    if (grid[x][y] <= grid[i][j]) {
                        if (cost < visited[x][y][remainingK - 1]) {
                            visited[x][y][remainingK - 1] = cost;
                            pq.enqueue([cost, x, y, remainingK - 1]);
                        }
                    }
                }
            }
        }
    }
    return -1;
}
